/* globals console, window, document */

const additionalMergeFieldsConfig = {
	previewModes: [ '$defaultValues' ],
	initialPreviewMode: '$defaultValues',
	definitions: [
		{
			id: 'bitcoinRate',
			label: 'Bitcoin rate',
			defaultValue: editor =>	{
				if ( !editor.plugins.has( 'IntervalFetcher' ) ) {
					return 'Data not available.';
				}

				return editor.plugins.get( 'IntervalFetcher' ).mergeFieldsData.bitcoinRate || 'Fetching data...';
			}
		}
	]
};

window.ClassicEditor
	.create( document.querySelector( '#snippet-merge-fields-refresh-values' ), {
		mergeFields: { ...window.ClassicEditor.defaultConfig.mergeFields, ...additionalMergeFieldsConfig },
		toolbar: {
			items: [
				'insertMergeField'
			].concat( window.ClassicEditor.defaultConfig.toolbar.items )
		},
		extraPlugins: [ window.CKEditorPlugins.IntervalFetcher ]
	} )
	.then( editor => {
		window.editor = editor;

		// Prevent showing a warning notification when user is pasting a content from MS Word or Google Docs.
		window.preventPasteFromOfficeNotification = true;

		window.attachTourBalloon( {
			target: window.findToolbarItem(
				editor.ui.view.toolbar, item => item.buttonView && item.buttonView.label === 'Insert merge field'
			),
			text: '"Bitcoin rate" merge field value refreshes every 5 seconds.',
			editor,
			tippyOptions: {
				placement: 'bottom-start'
			}
		} );
	} )
	.catch( err => {
		console.error( err.stack );
	} );
